# Find all substrings inside straight double quotes:
subs = []
i = 0
while True:
    start = text.find('"', i)
    if start == -1:
        break
    end = text.find('"', start+1)
    if end == -1:
        break
    subs.append((start, end, text[start+1:end]))
    i = end+1

len(subs), subs[:20]
